#!/usr/bin/env python3
"""
Dependency Lock File Management Tool

This script provides utilities for managing Python dependency lock files
with cryptographic hashes to ensure package integrity and consistent
dependency versions across development and production environments.

Supports:
- requirements.txt with SHA256 hashes
- Poetry lock files
- Dependency updates with integrity verification
- Security vulnerability scanning
"""

import hashlib
import json
import subprocess
import sys
import os
import re
from pathlib import Path
from typing import List, Dict, Optional, Tuple
from urllib.request import urlopen
from urllib.parse import urlparse
import tempfile
import shutil


class DependencyManager:
    """Manages Python dependency lock files with integrity verification."""
    
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root).resolve()
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_lock = self.project_root / "requirements-lock.txt"
        self.pyproject_file = self.project_root / "pyproject.toml"
        self.poetry_lock = self.project_root / "poetry.lock"
        
    def generate_requirements_lock(self, input_file: Optional[str] = None) -> None:
        """
        Generate a locked requirements file with SHA256 hashes for all dependencies.
        
        Args:
            input_file: Path to input requirements.txt (default: requirements.txt)
        """
        input_path = Path(input_file) if input_file else self.requirements_file
        
        if not input_path.exists():
            raise FileNotFoundError(f"Requirements file not found: {input_path}")
        
        print(f"Generating locked requirements from {input_path}...")
        
        # Create a temporary virtual environment for clean resolution
        with tempfile.TemporaryDirectory() as tmpdir:
            venv_path = Path(tmpdir) / "venv"
            
            # Create virtual environment
            subprocess.run(
                [sys.executable, "-m", "venv", str(venv_path)],
                check=True,
                capture_output=True
            )
            
            # Determine pip executable path
            if sys.platform == "win32":
                pip_exe = venv_path / "Scripts" / "pip.exe"
            else:
                pip_exe = venv_path / "bin" / "pip"
            
            # Upgrade pip to latest version
            subprocess.run(
                [str(pip_exe), "install", "--upgrade", "pip"],
                check=True,
                capture_output=True
            )
            
            # Install dependencies
            subprocess.run(
                [str(pip_exe), "install", "-r", str(input_path)],
                check=True,
                capture_output=True
            )
            
            # Generate locked requirements with hashes
            result = subprocess.run(
                [str(pip_exe), "freeze", "--all"],
                check=True,
                capture_output=True,
                text=True
            )
            
            frozen_deps = result.stdout.strip().split('\n')
            
            # Download packages and compute hashes
            locked_requirements = []
            locked_requirements.append("# Generated lock file with SHA256 hashes")
            locked_requirements.append("# DO NOT EDIT MANUALLY - Use dependency manager tool")
            locked_requirements.append("")
            
            for dep in frozen_deps:
                if not dep or dep.startswith('#'):
                    continue
                    
                # Parse package name and version
                match = re.match(r'^([a-zA-Z0-9\-_.]+)==([0-9.]+.*?)$', dep.strip())
                if not match:
                    continue
                    
                package_name, version = match.groups()
                
                # Download package to get hash
                download_result = subprocess.run(
                    [str(pip_exe), "download", "--no-deps", f"{package_name}=={version}",
                     "--dest", tmpdir],
                    capture_output=True,
                    text=True
                )
                
                if download_result.returncode != 0:
                    print(f"Warning: Could not download {package_name}=={version}")
                    locked_requirements.append(dep)
                    continue
                
                # Find downloaded file and compute hash
                downloaded_files = list(Path(tmpdir).glob(f"{package_name.replace('-', '_')}*"))
                if not downloaded_files:
                    downloaded_files = list(Path(tmpdir).glob(f"{package_name}*"))
                
                if downloaded_files:
                    package_file = downloaded_files[0]
                    sha256_hash = self._compute_file_hash(package_file)
                    locked_requirements.append(
                        f"{package_name}=={version} \\\n"
                        f"    --hash=sha256:{sha256_hash}"
                    )
                    # Clean up downloaded file
                    package_file.unlink()
                else:
                    locked_requirements.append(dep)
        
        # Write locked requirements
        with open(self.requirements_lock, 'w', encoding='utf-8') as f:
            f.write('\n'.join(locked_requirements))
        
        print(f"✓ Generated locked requirements: {self.requirements_lock}")
    
    def _compute_file_hash(self, file_path: Path) -> str:
        """Compute SHA256 hash of a file."""
        sha256 = hashlib.sha256()
        with open(file_path, 'rb') as f:
            while chunk := f.read(8192):
                sha256.update(chunk)
        return sha256.hexdigest()
    
    def verify_lock_file(self, lock_file: Optional[str] = None) -> bool:
        """
        Verify integrity of a lock file by checking hashes.
        
        Args:
            lock_file: Path to lock file (default: requirements-lock.txt)
            
        Returns:
            True if all hashes verify successfully
        """
        lock_path = Path(lock_file) if lock_file else self.requirements_lock
        
        if not lock_path.exists():
            raise FileNotFoundError(f"Lock file not found: {lock_path}")
        
        print(f"Verifying lock file: {lock_path}")
        
        with tempfile.TemporaryDirectory() as tmpdir:
            venv_path = Path(tmpdir) / "venv"
            
            # Create virtual environment
            subprocess.run(
                [sys.executable, "-m", "venv", str(venv_path)],
                check=True,
                capture_output=True
            )
            
            if sys.platform == "win32":
                pip_exe = venv_path / "Scripts" / "pip.exe"
            else:
                pip_exe = venv_path / "bin" / "pip"
            
            # Upgrade pip
            subprocess.run(
                [str(pip_exe), "install", "--upgrade", "pip"],
                check=True,
                capture_output=True
            )
            
            # Install with hash checking (pip will verify hashes automatically)
            result = subprocess.run(
                [str(pip_exe), "install", "--require-hashes", "-r", str(lock_path)],
                capture_output=True,
                text=True
            )
            
            if result.returncode == 0:
                print("✓ All package hashes verified successfully")
                return True
            else:
                print("✗ Hash verification failed:")
                print(result.stderr)
                return False
    
    def update_dependency(self, package_name: str, version: Optional[str] = None) -> None:
        """
        Update a specific dependency to a new version and regenerate lock file.
        
        Args:
            package_name: Name of the package to update
            version: Specific version to update to (default: latest)
        """
        print(f"Updating {package_name}...")
        
        # Read current requirements
        if not self.requirements_file.exists():
            raise FileNotFoundError(f"Requirements file not found: {self.requirements_file}")
        
        with open(self.requirements_file, 'r', encoding='utf-8') as f:
            lines = f.readlines()
        
        # Update the package version
        updated = False
        new_lines = []
        
        for line in lines:
            if line.strip().startswith(package_name):
                if version:
                    new_lines.append(f"{package_name}=={version}\n")
                else:
                    new_lines.append(f"{package_name}\n")
                updated = True
            else:
                new_lines.append(line)
        
        if not updated:
            # Add new dependency
            if version:
                new_lines.append(f"{package_name}=={version}\n")
            else:
                new_lines.append(f"{package_name}\n")
        
        # Write updated requirements
        with open(self.requirements_file, 'w', encoding='utf-8') as f:
            f.writelines(new_lines)
        
        # Regenerate lock file
        self.generate_requirements_lock()
        
        print(f"✓ Updated {package_name}")
    
    def check_security_vulnerabilities(self) -> Dict[str, List[str]]:
        """
        Check for known security vulnerabilities in dependencies using pip-audit.
        
        Returns:
            Dictionary of vulnerable packages and their issues
        """
        print("Checking for security vulnerabilities...")
        
        # Try to use pip-audit if available
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip_audit", "-r", str(self.requirements_lock)],
                capture_output=True,
                text=True,
                timeout=60
            )
            
            if result.returncode == 0:
                print("✓ No known vulnerabilities found")
                return {}
            else:
                print("⚠ Vulnerabilities detected:")
                print(result.stdout)
                
                # Parse vulnerabilities
                vulnerabilities = {}
                current_package = None
                
                for line in result.stdout.split('\n'):
                    if line.strip() and not line.startswith('-'):
                        if '==' in line:
                            current_package = line.split('==')[0].strip()
                            vulnerabilities[current_package] = []
                        elif current_package:
                            vulnerabilities[current_package].append(line.strip())
                
                return vulnerabilities
                
        except (subprocess.TimeoutExpired, FileNotFoundError):
            print("⚠ pip-audit not available. Install with: pip install pip-audit")
            return {}
    
    def poetry_lock_generate(self) -> None:
        """Generate or update Poetry lock file."""
        if not self.pyproject_file.exists():
            raise FileNotFoundError(f"pyproject.toml not found: {self.pyproject_file}")
        
        print("Generating Poetry lock file...")
        
        result = subprocess.run(
            ["poetry", "lock", "--no-update"],
            cwd=str(self.project_root),
            capture_output=True,
            text=True
        )
        
        if result.returncode == 0:
            print(f"✓ Generated Poetry lock file: {self.poetry_lock}")
        else:
            print("✗ Failed to generate Poetry lock file:")
            print(result.stderr)
            raise RuntimeError("Poetry lock generation failed")
    
    def poetry_lock_verify(self) -> bool:
        """Verify Poetry lock file is up to date."""
        if not self.poetry_lock.exists():
            raise FileNotFoundError(f"poetry.lock not found: {self.poetry_lock}")
        
        print("Verifying Poetry lock file...")
        
        result = subprocess.run(
            ["poetry", "lock", "--check"],
            cwd=str(self.project_root),
            capture_output=True,
            text=True
        )
        
        if result.returncode == 0:
            print("✓ Poetry lock file is up to date")
            return True
        else:
            print("✗ Poetry lock file is out of date")
            print(result.stderr)
            return False
    
    def export_poetry_to_requirements(self) -> None:
        """Export Poetry dependencies to requirements.txt format with hashes."""
        if not self.poetry_lock.exists():
            raise FileNotFoundError(f"poetry.lock not found: {self.poetry_lock}")
        
        print("Exporting Poetry dependencies to requirements.txt...")
        
        result = subprocess.run(
            ["poetry", "export", "-f", "requirements.txt", "--output",
             str(self.requirements_lock), "--with-credentials"],
            cwd=str(self.project_root),
            capture_output=True,
            text=True
        )
        
        if result.returncode == 0:
            print(f"✓ Exported to {self.requirements_lock}")
        else:
            print("✗ Export failed:")
            print(result.stderr)
            raise RuntimeError("Poetry export failed")
    
    def generate_dependency_report(self) -> Dict:
        """Generate a comprehensive dependency report."""
        report = {
            "project_root": str(self.project_root),
            "dependencies": [],
            "lock_file_status": {},
            "security_check": {}
        }
        
        # Check which lock files exist
        report["lock_file_status"]["requirements_lock"] = self.requirements_lock.exists()
        report["lock_file_status"]["poetry_lock"] = self.poetry_lock.exists()
        
        # Parse dependencies
        if self.requirements_lock.exists():
            with open(self.requirements_lock, 'r', encoding='utf-8') as f:
                for line in f:
                    line = line.strip()
                    if line and not line.startswith('#') and '==' in line:
                        match = re.match(r'^([a-zA-Z0-9\-_.]+)==([0-9.]+.*?)(?:\s|$)', line)
                        if match:
                            pkg_name, version = match.groups()
                            has_hash = '--hash=' in line
                            report["dependencies"].append({
                                "name": pkg_name,
                                "version": version,
                                "has_hash": has_hash
                            })
        
        # Security check
        vulnerabilities = self.check_security_vulnerabilities()
        report["security_check"]["vulnerabilities"] = vulnerabilities
        report["security_check"]["vulnerable_count"] = len(vulnerabilities)
        
        return report


def main():
    """Main CLI interface for dependency management."""
    import argparse
    
    parser = argparse.ArgumentParser(
        description="Python Dependency Lock File Manager with Integrity Verification"
    )
    parser.add_argument(
        "--project-root",
        default=".",
        help="Project root directory (default: current directory)"
    )
    
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")
    
    # Generate lock file
    gen_parser = subparsers.add_parser("generate", help="Generate locked requirements file")
    gen_parser.add_argument(
        "--input",
        help="Input requirements file (default: requirements.txt)"
    )
    
    # Verify lock file
    verify_parser = subparsers.add_parser("verify", help="Verify lock file integrity")
    verify_parser.add_argument(
        "--lock-file",
        help="Lock file to verify (default: requirements-lock.txt)"
    )
    
    # Update dependency
    update_parser = subparsers.add_parser("update", help="Update a dependency")
    update_parser.add_argument("package", help="Package name to update")
    update_parser.add_argument("--version", help="Specific version to update to")
    
    # Security check
    subparsers.add_parser("security-check", help="Check for security vulnerabilities")
    
    # Poetry commands
    subparsers.add_parser("poetry-lock", help="Generate Poetry lock file")
    subparsers.add_parser("poetry-verify", help="Verify Poetry lock file")
    subparsers.add_parser("poetry-export", help="Export Poetry to requirements.txt")
    
    # Report
    subparsers.add_parser("report", help="Generate dependency report")
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        return
    
    manager = DependencyManager(args.project_root)
    
    try:
        if args.command == "generate":
            manager.generate_requirements_lock(args.input)
        
        elif args.command == "verify":
            success = manager.verify_lock_file(args.lock_file)
            sys.exit(0 if success else 1)
        
        elif args.command == "update":
            manager.update_dependency(args.package, args.version)
        
        elif args.command == "security-check":
            vulnerabilities = manager.check_security_vulnerabilities()
            sys.exit(0 if not vulnerabilities else 1)
        
        elif args.command == "poetry-lock":
            manager.poetry_lock_generate()
        
        elif args.command == "poetry-verify":
            success = manager.poetry_lock_verify()
            sys.exit(0 if success else 1)
        
        elif args.command == "poetry-export":
            manager.export_poetry_to_requirements()
        
        elif args.command == "report":
            report = manager.generate_dependency_report()
            print("\n" + "="*60)
            print("DEPENDENCY REPORT")
            print("="*60)
            print(json.dumps(report, indent=2))
    
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()